27	/**
28	 * Dashboard — landing page after login.
29	 *
30	 * Patron sculpture: **Sisyphus**, rendered huge and dim on the right
31	 * side of the page. The daily act of returning to the Codex — scanning
32	 * newly-synthesized conclusions, picking up where yesterday's
33	 * deliberation left off, discovering the contradictions that drifted
34	 * overnight — is the boulder at firm-memory scale. The reward for a
35	 * round of work well done is another round of work: the dashboard is
36	 * the summit the figure never quite reaches, and the page is the
37	 * fresh slope they return to.
38	 */
39	
40	async function getDashboardConclusions(tenant: TenantContext) {
41	  return db.conclusion.findMany({
42	    where: {
43	      organizationId: tenant.organizationId,
44	      // Hide conclusions this founder has dismissed from their
45	      // dashboard. Other founders' dashboards are unaffected.
46	      dashboardDismissals: {
47	        none: { founderId: tenant.founderId },
48	      },
49	    },
50	    orderBy: { createdAt: "desc" },
51	    take: 8,
52	  });
53	}
54	
55	type DashboardConclusion = Awaited<
56	  ReturnType<typeof getDashboardConclusions>
57	>[number];
58	
59	async function getHiddenDashboardConclusionCount(tenant: TenantContext) {
60	  return db.dashboardDismissal.count({
61	    where: {
62	      founderId: tenant.founderId,
63	      conclusion: { organizationId: tenant.organizationId },
64	    },
65	  });
66	}
67	
68	function toDashboardConclusionCard(
69	  conclusion: DashboardConclusion,
70	): DashboardConclusionCard {
71	  return {
72	    id: conclusion.id,
73	    confidenceTier: conclusion.confidenceTier,
74	    topicHint: conclusion.topicHint,
75	    text: conclusion.text,
76	  };
77	}
