81	  if (!tenant) {
82	    return null;
83	  }
84	
85	  const [conclusions, hiddenConclusionCount] = await Promise.all([
86	    getDashboardConclusions(tenant),
87	    getHiddenDashboardConclusionCount(tenant),
88	  ]);
89	
90	  return (
91	    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
92	      <DashboardKeymap />
93	      <SculptureBackdrop src="/sculptures/sisyphus.mesh.bin" side="right" />
94	
95	      <main
96	        style={{
97	          position: "relative",
98	          zIndex: 1,
99	          maxWidth: "1100px",
100	          margin: "0 auto",
101	          padding: "2rem 2rem 3rem",
102	        }}
103	      >
104	        <header className="page-header">
105	          <div className="page-header__lead">
106	            <p className="page-header__kicker">Operator console</p>
107	            <h1 className="page-header__title">Forum</h1>
108	            <p className="page-header__desc">
109	              Welcome back, {tenant.founderName}. Recent work, attention items,
110	              and processing health are below.
111	            </p>
112	          </div>
113	        </header>
114	
115	        {!tenant.founderDisplayName && !tenant.accountNudgeDismissedAt ? (
116	          <AccountDisplayNameNudge />
117	        ) : null}
118	
119	        <AutoProcessStatusBanner />
120	
121	        {/*
122	         * Primary surface: the unified attention queue.
123	         *
124	         * Older versions of this dashboard surfaced a different queue
125	         * per panel — drift, contradictions, source-triage, etc. —
126	         * which made it easy to miss high-severity items because each
127	         * was a tab away. The Attention queue collapses every
128	         * founder-side queue into one ranked list (severity → age →
129	         * queue id), so "what needs your attention right now" is the
130	         * first thing the founder sees on login. Pulse / Hearth-style
131	         * ambient indicators move to a secondary row below.
132	         */}
133	        <Suspense fallback={null}>
134	          <AttentionPanel tenant={tenant} />
135	        </Suspense>
136	
137	        <div
138	          style={{
139	            display: "grid",
140	            gap: "1rem",
141	            gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
142	            marginBottom: "1.25rem",
