154	        </Suspense>
155	        <Suspense fallback={null}>
156	          <UploadWorkStatus tenant={tenant} />
157	        </Suspense>
158	        <Suspense fallback={null}>
159	          <PendingUploadDeletionSignal tenant={tenant} />
160	        </Suspense>
161	
162	        <div
163	          style={{
164	            display: "flex",
165	            justifyContent: "flex-end",
166	            alignItems: "center",
167	            marginBottom: "1.25rem",
168	            gap: "0.75rem",
169	          }}
170	        >
