223	function healthProblems(health: CurrentsHealth | null): string[] {
224	  if (!health) return ["Currents health endpoint is unreachable."];
225	  const problems = [...health.disabled_reasons];
226	  if (!health.last_cycle_at) problems.push("scheduler has not reported a cycle");
227	  if (health.events_last_24h === 0) problems.push("no X events recorded in the last 24h");
228	  if (health.opinions_last_24h === 0) problems.push("no Currents opinions generated in the last 24h");
229	  return problems;
230	}
