247	  const problems = healthProblems(health);
248	  const healthy = problems.length === 0;
249	  const accent = healthy ? "rgba(160, 211, 170, 0.9)" : "var(--ember)";
250	  const embeddingAccent = embeddingHealthColor(embeddingsHealthy);
251	
252	  return (
253	    <section
254	      aria-label="Currents operator pulse"
255	      style={{
256	        border: `1px solid ${accent}`,
257	        borderRadius: 4,
258	        padding: "0.85rem 1rem",
259	        background: healthy ? "rgba(95, 126, 93, 0.12)" : "rgba(172, 54, 37, 0.12)",
