261	    >
262	      <div
263	        style={{
264	          display: "flex",
265	          justifyContent: "space-between",
266	          gap: "1rem",
267	          alignItems: "baseline",
268	          flexWrap: "wrap",
269	        }}
270	      >
271	        <div
272	          className="mono"
273	          style={{
274	            color: accent,
275	            fontSize: "0.66rem",
276	            letterSpacing: "0.18em",
277	            textTransform: "uppercase",
278	          }}
279	        >
280	          Currents · {healthy ? "live" : "attention"}
