289	          : problems.join("; ")}
290	      </p>
291	      {health ? (
292	        <p className="mono" style={{ color: "var(--parchment-dim)", fontSize: "0.68rem", margin: "0.45rem 0 0" }}>
293	          token={health.x_bearer_present ? "present" : "missing"} · curated=
294	          {health.curated_count} · search={health.search_count}
295	        </p>
296	      ) : null}
297	      <p
298	        className="mono"
299	        style={{
300	          display: "flex",
301	          alignItems: "center",
302	          gap: "0.45rem",
303	          color: "var(--parchment-dim)",
304	          fontSize: "0.68rem",
305	          margin: "0.45rem 0 0",
306	        }}
307	      >
308	        <span
309	          aria-hidden="true"
310	          style={{
311	            width: 8,
312	            height: 8,
313	            borderRadius: "50%",
314	            background: embeddingAccent,
315	            boxShadow: `0 0 8px ${embeddingAccent}`,
316	            display: "inline-block",
317	          }}
318	        />
319	        embeddingsHealthy=
320	        {embeddingsHealthy
321	          ? `${embeddingsHealthy.embeddedCount}/${embeddingsHealthy.totalCount}`
322	          : "unknown"}
323	      </p>
324	    </section>
325	  );
326	}
