328	async function ForecastsPulse({ tenant }: { tenant: TenantContext }) {
329	  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
330	  const [surface, settledLastWeek] = await Promise.all([
331	    getForecastPortfolioSurface(tenant.organizationId).catch((err) => {
332	      console.error("[dashboard] forecasts portfolio query failed:", err);
333	      return null;
334	    }),
335	    db.forecastBet
336	      .findMany({
337	        where: {
338	          organizationId: tenant.organizationId,
339	          mode: "PAPER",
340	          status: "SETTLED",
341	          settledAt: { gte: weekAgo },
342	        },
343	        select: { settlementPnlUsd: true },
344	      })
345	      .catch((err) => {
346	        console.error("[dashboard] forecasts pnl query failed:", err);
347	        return [];
348	      }),
349	  ]);
350	
351	  const mode = surface?.mode.mode ?? "GATE-BLOCKED";
352	  const accent =
353	    mode === "PAPER"
354	      ? "rgba(160, 211, 170, 0.9)"
355	      : mode === "LIVE"
356	        ? "var(--amber)"
357	        : "var(--ember)";
358	  const pnl7d = settledLastWeek.reduce((sum, row) => sum + Number(row.settlementPnlUsd ?? 0), 0);
359	
360	  return (
361	    <section
362	      aria-label="Forecasts portfolio pulse"
363	      style={{
364	        background: mode === "GATE-BLOCKED" ? "rgba(172, 54, 37, 0.12)" : "rgba(205, 151, 67, 0.08)",
365	        border: `1px solid ${accent}`,
366	        borderRadius: 4,
367	        padding: "0.85rem 1rem",
368	      }}
369	    >
370	      <div
371	        style={{
372	          alignItems: "baseline",
373	          display: "flex",
374	          flexWrap: "wrap",
375	          gap: "1rem",
376	          justifyContent: "space-between",
377	        }}
378	      >
379	        <div
380	          className="mono"
381	          style={{
382	            color: accent,
383	            fontSize: "0.66rem",
384	            letterSpacing: "0.18em",
385	            textTransform: "uppercase",
386	          }}
387	        >
388	          Forecasts / {mode}
389	        </div>
390	        <Link href="/forecasts/portfolio" style={{ color: "var(--gold)", fontSize: "0.78rem" }}>
391	          Open portfolio
392	        </Link>
393	      </div>
394	      <p style={{ color: "var(--parchment)", fontSize: "0.86rem", margin: "0.55rem 0 0" }}>
395	        Paper P&L 7d: {formatDashboardUsd(pnl7d)}; open positions: {surface?.kpis.openPositions ?? 0}.
396	      </p>
397	      {surface?.mode.failedGates.length ? (
398	        <p className="mono" style={{ color: "var(--ember)", fontSize: "0.68rem", margin: "0.45rem 0 0" }}>
399	          blocked={surface.mode.failedGates.map((gate) => gate.gateName).join(", ")}
400	        </p>
401	      ) : null}
402	    </section>
403	  );
404	}
