406	function formatDashboardUsd(value: number): string {
407	  const formatted = new Intl.NumberFormat("en-US", {
408	    currency: "USD",
409	    maximumFractionDigits: 2,
410	    minimumFractionDigits: 2,
411	    style: "currency",
412	  }).format(Math.abs(value));
413	  return value < 0 ? `-${formatted}` : value > 0 ? `+${formatted}` : formatted;
414	}
