416	function embeddingHealthColor(health: EmbeddingHealth | null): string {
417	  if (!health) return "var(--ember)";
418	  if (health.status === "red") return "var(--ember)";
419	  if (health.status === "amber") return "var(--amber)";
420	  return "rgba(160, 211, 170, 0.9)";
421	}
