423	function getUploadVisibilityScope(tenant: TenantContext): Prisma.UploadWhereInput {
424	  return {
425	    OR: [
426	      { visibility: { not: "private" } },
427	      { founderId: tenant.founderId },
428	    ],
429	  };
430	}
