432	async function AttentionPanel({ tenant }: { tenant: TenantContext }) {
433	  let listing;
434	  try {
435	    listing = await listAttentionForFounder(tenant);
436	  } catch (err) {
437	    console.error("[dashboard] attention listing failed:", err);
438	    listing = {
439	      items: [],
440	      dismissalRates: [],
441	      generatedAt: new Date(),
442	    };
443	  }
444	  const generatedAt = listing.generatedAt;
445	  return (
446	    <AttentionQueue
447	      items={listing.items.map((item) => ({
448	        queue: item.queue,
449	        itemId: item.itemId,
450	        severity: item.severity,
451	        ageMs: generatedAt.getTime() - item.createdAt.getTime(),
452	        createdAt: item.createdAt.toISOString(),
453	        preview: item.preview,
454	        link: item.link,
455	      }))}
456	      dismissalRates={listing.dismissalRates}
457	      generatedAt={generatedAt.toISOString()}
458	    />
459	  );
460	}
