485	          }}
486	        >
487	          <div
488	            style={{
489	              fontFamily: "'Cinzel', serif",
490	              fontSize: "0.65rem",
491	              letterSpacing: "0.15em",
492	              textTransform: "uppercase",
493	              color: "var(--ember)",
