507	            <p style={{ fontSize: "0.85rem", color: "var(--parchment)", margin: "0.25rem 0" }}>
508	              {decaying.length} decaying conclusion
509	              {decaying.length > 1 ? "s" : ""} — confidence is declining.
510	            </p>
511	          )}
512	          <Link
513	            href="/ops?panel=decay"
514	            style={{
515	              display: "inline-block",
516	              marginTop: "0.5rem",
517	              fontSize: "0.7rem",
518	              color: "var(--gold)",
519	              textDecoration: "none",
520	            }}
521	          >
522	            View decay dashboard →
523	          </Link>
524	        </div>
525	      )}
526	
527	      {unseenResponses > 0 && (
528	        <Link href="/responses" style={{ textDecoration: "none", display: "block" }}>
529	          <div
530	            className="portal-card"
531	            style={{
532	              padding: "0.7rem 1rem",
533	              marginBottom: "1rem",
534	              display: "flex",
535	              justifyContent: "space-between",
536	              alignItems: "center",
537	              fontSize: "0.8rem",
538	              borderLeft: "3px solid var(--amber)",
539	            }}
540	          >
541	            <span style={{ color: "var(--amber)" }}>
542	              {unseenResponses} unseen structured response
543	              {unseenResponses > 1 ? "s" : ""}
544	            </span>
545	            <span
546	              className="mono"
547	              style={{
548	                fontSize: "0.6rem",
549	                color: "var(--amber-dim)",
550	                textTransform: "uppercase",
551	              }}
552	            >
553	              Open inbox -&gt;
554	            </span>
555	          </div>
556	        </Link>
557	      )}
558	
559	      {activeContradictions > 0 && (
560	        <Link href="/ops?panel=contradictions" style={{ textDecoration: "none", display: "block" }}>
561	          <div
562	            className="portal-card"
563	            style={{
564	              padding: "0.7rem 1rem",
565	              marginBottom: "1rem",
566	              display: "flex",
567	              justifyContent: "space-between",
568	              alignItems: "center",
569	              fontSize: "0.8rem",
