625	async function getActiveContradictionCount(tenant: TenantContext) {
626	  try {
627	    return await db.contradiction.count({
628	      where: {
629	        organizationId: tenant.organizationId,
630	        status: "active",
631	      },
632	    });
633	  } catch {
634	    try {
635	      return await db.contradiction.count({
636	        where: { organizationId: tenant.organizationId },
637	      });
638	    } catch {
639	      return 0;
640	    }
641	  }
642	}
