670	async function UploadWorkStatus({ tenant }: { tenant: TenantContext }) {
671	  const visibilityScope = getUploadVisibilityScope(tenant);
672	  let pendingUploads = 0;
673	  let failedUploads = 0;
674	  try {
675	    [pendingUploads, failedUploads] = await Promise.all([
676	      db.upload.count({
677	        where: {
