1063	/** Small positive int → Roman numerals, for display accents only. */
1064	function toRoman(n: number): string {
1065	  if (!n || n < 1) return "";
1066	  const table: [number, string][] = [
1067	    [10, "X"],
1068	    [9, "IX"],
1069	    [5, "V"],
1070	    [4, "IV"],
1071	    [1, "I"],
1072	  ];
1073	  let out = "";
1074	  let rem = n;
1075	  for (const [v, s] of table) {
1076	    while (rem >= v) {
1077	      out += s;
1078	      rem -= v;
1079	    }
1080	  }
1081	  return out;
1082	}
