async function RecentUploadsPanel({ tenant }: { tenant: TenantContext }) {
  const recentUploadsArgs = {
    where: {
      organizationId: tenant.organizationId,
      deletedAt: null,
      ...getUploadVisibilityScope(tenant),
    },
    orderBy: { createdAt: "desc" },
    take: 12,
    select: {
      id: true,
      title: true,
      status: true,
      errorMessage: true,
      extractionMethod: true,
      visibility: true,
      publishedAt: true,
      slug: true,
      createdAt: true,
      founder: { select: { displayName: true, name: true, username: true } },
    },
  } satisfies Prisma.UploadFindManyArgs;
  let recentUploads: Prisma.UploadGetPayload<typeof recentUploadsArgs>[] = [];
  try {
    recentUploads = await db.upload.findMany(recentUploadsArgs);
  } catch (err) {
    console.error("[dashboard] recent upload query failed (schema lag?):", err);
  }

  return (
    <section
      className="ascii-frame"
      data-label={`UPLOADS · ${toRoman(recentUploads.length) || "0"}`}
    >
      <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
        {recentUploads.length === 0 ? (
          <LatinEmpty
            latin="No uploads yet."
            english="Nothing has been ingested yet."
          />
        ) : (
          recentUploads.map((u) => (
            <div key={u.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
              <div
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  gap: "1rem",
                  alignItems: "flex-start",
                }}
              >
                <div style={{ minWidth: 0, flex: 1 }}>
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "0.45rem",
                      overflow: "hidden",
                      flexWrap: "wrap",
                    }}
                  >
                    <Link
                      href={`/upload/${u.id}`}
                      style={{
                        fontFamily: "'EB Garamond', serif",
                        color: "var(--parchment)",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        textDecoration: "none",
                        whiteSpace: "nowrap",
                        minWidth: 0,
                      }}
                    >
                      {u.title}
                    </Link>
                    <UploadStatusBadge status={u.status} />
                    {u.visibility === "private" ? (
                      <span
                        className="mono"
                        title="Private — only you see this row. Noosphere still analyses it."
                        style={{
                          fontSize: "0.5rem",
                          letterSpacing: "0.22em",
                          textTransform: "uppercase",
                          color: "var(--amber)",
                          border: "1px solid var(--amber-dim)",
                          padding: "0.08rem 0.38rem",
                          borderRadius: "2px",
                          flexShrink: 0,
                        }}
                      >
                        Private
                      </span>
                    ) : u.visibility === "semi-private" ? (
                      <span
                        className="mono"
                        title="Semi-private — firm sees this; public blog never does. Noosphere still analyses it."
                        style={{
                          fontSize: "0.5rem",
                          letterSpacing: "0.22em",
                          textTransform: "uppercase",
                          color: "var(--amber)",
                          border: "1px solid var(--amber-dim)",
                          padding: "0.08rem 0.38rem",
                          borderRadius: "2px",
                          flexShrink: 0,
                        }}
                      >
                        Semi-private
                      </span>
                    ) : null}
                  </div>
                  <div
                    className="mono"
                    style={{
                      fontSize: "0.65rem",
                      color: "var(--parchment-dim)",
                      marginTop: "0.25rem",
                    }}
                  >
                    {founderDisplayName(u.founder)} · {new Date(u.createdAt).toLocaleDateString()}
                  </div>
                  <UploadRowDetail upload={u} />
                </div>
                <div
                  style={{
                    display: "flex",
                    gap: "0.5rem",
                    alignItems: "center",
                    flexShrink: 0,
                    flexWrap: "wrap",
                    justifyContent: "flex-end",
                  }}
                >
                  {u.status === "ingested" ? (
                    <PublishToggle
                      uploadId={u.id}
                      initialPublishedAt={u.publishedAt}
                      initialSlug={u.slug}
                    />
                  ) : null}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </section>
  );
}

async function DriftEventsPanel({ tenant }: { tenant: TenantContext }) {
  const drifts = await db.driftEvent.findMany({
    where: { organizationId: tenant.organizationId },
    orderBy: { observedAt: "desc" },
    take: 6,
  });

  return (
    <section
      className="ascii-frame"
      data-label={`DRIFT EVENTS · ${toRoman(drifts.length) || "0"}`}
      style={{ marginTop: "0.5rem" }}
    >
      {drifts.length === 0 ? (
        <LatinEmpty
          latin="No drift observed."
          english="The foundations are firm."
        />
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
          {drifts.map((d) => (
            <div key={d.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
              <div className="mono" style={{ fontSize: "0.72rem", color: "var(--ember)" }}>
                score {(d.driftScore * 100).toFixed(0)}% · {d.targetKind}{" "}
                {d.targetId.slice(0, 8)}…
              </div>
              <p
                style={{
                  marginTop: "0.35rem",
                  fontSize: "0.9rem",
                  color: "var(--parchment-dim)",
                  lineHeight: 1.5,
                }}
              >
                {d.naturalLanguageSummary || d.notes || "—"}
              </p>
              <div
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--parchment-dim)",
                  marginTop: "0.3rem",
                }}
              >
                {new Date(d.observedAt).toLocaleDateString()}
              </div>
            </div>
          ))}
        </div>
      )}
    </section>
  );
}

function DashboardSectionFallback({
  label,
  latin,
  english,
  style,
}: {
  label: string;
  latin: string;
  english: string;
  style?: CSSProperties;
}) {
  return (
    <section className="ascii-frame" data-label={label} style={style}>
      <LatinEmpty latin={latin} english={english} />
    </section>
  );
}

/**
 * Inline empty/loading state for populated `ascii-frame` sections.
 *
 * The prop names are historical: `latin` was an italic Latin tagline and
 * `english` a mono translation. Round 20 dropped the Latin from workflow
 * surfaces — both slots now take plain English copy, the `latin` slot
 * just renders larger.
 */
function LatinEmpty({ latin, english }: { latin: string; english: string }) {
  return (
    <div style={{ padding: "1rem 0.25rem", textAlign: "center" }}>
      <p
        style={{
          fontFamily: "'EB Garamond', serif",
          fontSize: "1rem",
          color: "var(--parchment)",
          margin: 0,
        }}
      >
        {latin}
      </p>
      <p
        className="mono"
        style={{
          fontSize: "0.7rem",
          color: "var(--parchment-dim)",
          marginTop: "0.25rem",
        }}
      >
        {english}
      </p>
    </div>
  );
}

/** Small positive int → Roman numerals, for display accents only. */
function toRoman(n: number): string {
  if (!n || n < 1) return "";
  const table: [number, string][] = [
    [10, "X"],
    [9, "IX"],
    [5, "V"],
    [4, "IV"],
    [1, "I"],
  ];
  let out = "";
  let rem = n;
  for (const [v, s] of table) {
    while (rem >= v) {
      out += s;
      rem -= v;
    }
  }
  return out;
}

