267	function ConclusionCard({
268	  conclusion,
269	  busy,
270	  onDismiss,
271	}: {
272	  conclusion: DashboardConclusionCard;
273	  busy: boolean;
274	  onDismiss: (conclusion: DashboardConclusionCard) => Promise<void>;
275	}) {
276	  return (
277	    <div
278	      data-testid="dashboard-conclusion-card"
279	      className="portal-card"
280	      style={{ padding: "0.9rem 1rem" }}
281	    >
282	      <div
283	        style={{
284	          display: "flex",
285	          gap: "0.9rem",
286	          alignItems: "flex-start",
287	        }}
288	      >
289	        <ConfidenceTierSigil tier={conclusion.confidenceTier} />
290	        <div style={{ minWidth: 0, flex: 1 }}>
291	          <div
292	            className="mono"
293	            style={{
294	              fontSize: "0.6rem",
295	              color: "var(--amber-dim)",
296	              textTransform: "uppercase",
297	              letterSpacing: "0.12em",
298	            }}
299	          >
