301	          </div>
302	          <p
303	            style={{
304	              marginTop: "0.4rem",
305	              marginBottom: 0,
306	              fontSize: "0.95rem",
307	              color: "var(--parchment)",
308	              lineHeight: 1.5,
309	            }}
310	          >
311	            {conclusion.text}
312	          </p>
313	        </div>
314	        <ConclusionActionMenu
315	          conclusion={conclusion}
316	          busy={busy}
317	          onDismiss={onDismiss}
318	        />
319	      </div>
320	    </div>
321	  );
322	}
323	
324	function ConclusionActionMenu({
325	  conclusion,
326	  busy,
327	  onDismiss,
328	}: {
329	  conclusion: DashboardConclusionCard;
330	  busy: boolean;
331	  onDismiss: (conclusion: DashboardConclusionCard) => Promise<void>;
332	}) {
333	  const [open, setOpen] = useState(false);
334	  const [showHint, setShowHint] = useState(false);
335	  const buttonRef = useRef<HTMLButtonElement | null>(null);
336	  const itemRefs = useRef<Array<HTMLButtonElement | HTMLAnchorElement | null>>([]);
337	  const tooltipId = useId();
338	  const menuId = useId();
339	
340	  useEffect(() => {
341	    if (!open) return;
342	    function onWindowPointerDown(event: PointerEvent) {
343	      const target = event.target as Node | null;
344	      if (!target) return;
345	      const button = buttonRef.current;
346	      const menuItems = itemRefs.current;
347	      if (button?.contains(target)) return;
348	      if (menuItems.some((item) => item?.contains(target))) return;
349	      setOpen(false);
350	    }
351	    window.addEventListener("pointerdown", onWindowPointerDown);
352	    return () => window.removeEventListener("pointerdown", onWindowPointerDown);
353	  }, [open]);
354	
355	  function focusItem(index: number) {
356	    itemRefs.current[index]?.focus();
357	  }
358	
359	  function openMenu(index = 0) {
360	    setOpen(true);
361	    window.requestAnimationFrame(() => focusItem(index));
362	  }
363	
364	  function closeMenu() {
365	    setOpen(false);
366	    window.requestAnimationFrame(() => buttonRef.current?.focus());
367	  }
368	
369	  function onButtonKeyDown(event: KeyboardEvent<HTMLButtonElement>) {
370	    if (
371	      event.key === "Enter" ||
372	      event.key === " " ||
373	      event.key === "ArrowDown"
374	    ) {
375	      event.preventDefault();
376	      openMenu(0);
377	    } else if (event.key === "ArrowUp") {
378	      event.preventDefault();
379	      openMenu(1);
380	    }
381	  }
382	
383	  function onMenuKeyDown(event: KeyboardEvent<HTMLDivElement>) {
384	    const activeIndex = itemRefs.current.findIndex(
385	      (item) => item === document.activeElement,
386	    );
387	    if (event.key === "ArrowDown") {
388	      event.preventDefault();
389	      focusItem(activeIndex >= 0 ? (activeIndex + 1) % 2 : 0);
390	    } else if (event.key === "ArrowUp") {
391	      event.preventDefault();
392	      focusItem(activeIndex >= 0 ? (activeIndex + 2 - 1) % 2 : 1);
393	    } else if (event.key === "Home") {
394	      event.preventDefault();
395	      focusItem(0);
396	    } else if (event.key === "End") {
397	      event.preventDefault();
398	      focusItem(1);
399	    } else if (event.key === "Escape") {
400	      event.preventDefault();
401	      closeMenu();
402	    } else if (event.key === "Tab") {
403	      setOpen(false);
404	    }
405	  }
406	
407	  const requestDeletionHref = `/library?request=${encodeURIComponent(
408	    conclusion.id,
409	  )}#conclusion-deletion-request`;
410	
411	  return (
412	    <div style={{ position: "relative", flexShrink: 0 }}>
413	      <button
414	        ref={buttonRef}
415	        type="button"
