420	        aria-label={`Conclusion actions for: ${truncate(conclusion.text, 72)}`}
421	        onClick={() => (open ? setOpen(false) : openMenu(0))}
422	        onKeyDown={onButtonKeyDown}
423	        onMouseEnter={() => setShowHint(true)}
424	        onMouseLeave={() => setShowHint(false)}
425	        onFocus={() => setShowHint(true)}
426	        onBlur={() => setShowHint(false)}
427	        disabled={busy}
428	        style={{
429	          display: "inline-flex",
430	          alignItems: "center",
431	          gap: "0.32rem",
432	          border: "1px solid var(--stroke)",
433	          background: "rgba(10, 10, 10, 0.26)",
434	          color: "var(--parchment-dim)",
435	          cursor: busy ? "default" : "pointer",
436	          fontFamily: "'Cinzel', serif",
437	          fontSize: "0.58rem",
438	          letterSpacing: "0.12em",
439	          textTransform: "uppercase",
440	          padding: "0.28rem 0.45rem",
441	          borderRadius: 2,
442	          lineHeight: 1,
443	          opacity: busy ? 0.45 : 0.92,
444	        }}
445	      >
446	        <EyeOff size={13} aria-hidden="true" />
447	        Actions
448	        <ChevronDown size={12} aria-hidden="true" />
449	      </button>
450	
451	      {showHint && !open ? (
452	        <div
453	          id={tooltipId}
454	          role="tooltip"
455	          style={{
