3	import { useEffect, useState } from "react";
4	
5	/**
6	 * Dashboard banner that surfaces the live state of auto-processing.
7	 *
8	 * Three states:
9	 *   - `loading`      → nothing rendered (brief; we don't want flicker)
10	 *   - `configured`   → small green pill in the corner: "AUTO-PROCESS ACTIVE"
11	 *   - `unconfigured` → prominent amber card with the exact setup steps,
12	 *                      pulled from the live /api/health/auto-processing
13	 *                      response so the copy tracks reality.
14	 *
15	 * Only shown to logged-in founders. Quietly fails if the health endpoint
16	 * returns 401/500 — we don't want this banner to block the dashboard
17	 * from rendering for an observability reason.
18	 */
19	
20	interface HealthResponse {
21	  configured: boolean;
22	  summary: string;
23	  vercel: {
24	    github_dispatch_token: boolean;
25	    github_dispatch_repo: string;
26	    openai_key: boolean;
27	  };
28	  github: {
29	    workflow_url: string;
30	  };
31	}
32	
33	export default function AutoProcessStatusBanner() {
34	  const [state, setState] = useState<"loading" | "ok" | "todo">("loading");
35	  const [data, setData] = useState<HealthResponse | null>(null);
36	
37	  useEffect(() => {
38	    let cancelled = false;
39	    fetch("/api/health/auto-processing")
40	      .then((r) => (r.ok ? r.json() : Promise.reject(r.status)))
41	      .then((d: HealthResponse) => {
42	        if (cancelled) return;
43	        setData(d);
44	        setState(d.configured ? "ok" : "todo");
45	      })
46	      .catch(() => {
47	        if (!cancelled) setState("ok"); // fail-quiet: hide the banner
