3	import { forwardRef } from "react";
4	import type {
5	  AnchorHTMLAttributes,
6	  ButtonHTMLAttributes,
7	  ReactNode,
8	} from "react";
9	
10	/**
11	 * Shared button vocabulary for workflow surfaces.
12	 *
13	 * Visual ladder, quietest to loudest:
14	 *   variant="ghost"   — no border, amber text, used inline
15	 *   variant="quiet"   — bordered, sentence-case, no Cinzel
16	 *   variant="default" — the existing `.btn` (Cinzel uppercase)
17	 *   variant="solid"   — filled amber (`.btn-solid`)
18	 *
19	 * State props:
20	 *   loading  — adds a spinner glyph, sets `aria-busy`, disables clicks
21	 *   success  — flashes a check glyph (caller resets after a tick)
22	 *   error    — flashes an error tone (caller resets after a tick)
23	 *
24	 * Disabled and loading look different: a disabled button is "not ready"
25	 * (greyed border, idle cursor); a loading button is "in flight"
26	 * (spinner + wait cursor). This distinction is the Round 20 contract
27	 * requirement (`§3.3`).
28	 */
29	type Variant = "ghost" | "quiet" | "default" | "solid";
30	type State = "idle" | "loading" | "success" | "error";
31	
32	type CommonProps = {
33	  variant?: Variant;
34	  state?: State;
35	  loading?: boolean;
36	  success?: boolean;
37	  error?: boolean;
38	  size?: "sm" | "md";
39	  children: ReactNode;
40	};
41	
42	type ButtonProps = CommonProps &
43	  Omit<ButtonHTMLAttributes<HTMLButtonElement>, "children"> & {
44	    as?: "button";
45	  };
46	
47	type AnchorProps = CommonProps &
48	  Omit<AnchorHTMLAttributes<HTMLAnchorElement>, "children"> & {
49	    as: "a";
50	    href: string;
51	  };
52	
53	export type ActionButtonProps = ButtonProps | AnchorProps;
54	
55	function classesFor(
56	  variant: Variant,
57	  size: "sm" | "md",
58	  state: State,
59	  extra?: string,
60	): string {
61	  const base = ["btn", `btn--${variant}`];
62	  if (size === "sm") base.push("btn--sm");
63	  if (state !== "idle") base.push(`btn--${state}`);
64	  if (extra) base.push(extra);
65	  return base.join(" ");
66	}
67	
68	function resolveState(
69	  state: State | undefined,
70	  loading: boolean | undefined,
71	  success: boolean | undefined,
72	  error: boolean | undefined,
73	): State {
74	  if (state && state !== "idle") return state;
75	  if (loading) return "loading";
76	  if (success) return "success";
77	  if (error) return "error";
78	  return "idle";
79	}
80	
81	const ActionButton = forwardRef<
82	  HTMLButtonElement | HTMLAnchorElement,
83	  ActionButtonProps
84	>(function ActionButton(props, ref) {
85	  const {
86	    variant = "default",
87	    size = "md",
88	    state,
89	    loading,
90	    success,
91	    error,
92	    children,
93	    className,
94	  } = props;
95	  const resolved = resolveState(state, loading, success, error);
96	  const isBusy = resolved === "loading";
97	  const classes = classesFor(variant, size, resolved, className);
98	  const content = (
99	    <>
100	      {isBusy ? <span className="btn-spinner" aria-hidden="true" /> : null}
101	      {resolved === "success" ? (
102	        <span className="btn-glyph" aria-hidden="true">
103	          ✓
104	        </span>
105	      ) : null}
106	      <span className="btn-label">{children}</span>
107	    </>
108	  );
109	
110	  if (props.as === "a") {
111	    // Anchor: forward role/aria so screen readers see button-like
112	    // semantics if the caller really meant a button-styled link.
113	    const { as: _as, ...rest } = props;
114	    void _as;
115	    return (
116	      <a
117	        ref={ref as React.Ref<HTMLAnchorElement>}
118	        {...rest}
119	        className={classes}
120	        aria-busy={isBusy ? "true" : undefined}
121	        data-state={resolved}
122	      >
123	        {content}
124	      </a>
125	    );
126	  }
127	
128	  const { as: _as, disabled, ...rest } = props as ButtonProps;
129	  void _as;
130	  return (
131	    <button
132	      ref={ref as React.Ref<HTMLButtonElement>}
133	      {...rest}
134	      disabled={disabled || isBusy}
135	      aria-busy={isBusy ? "true" : undefined}
136	      data-state={resolved}
137	      className={classes}
138	    >
139	      {content}
140	    </button>
141	  );
142	});
143	
144	export default ActionButton;
145

