        },
        select: { settlementPnlUsd: true },
      })
      .catch((err) => {
        console.error("[dashboard] forecasts pnl query failed:", err);
        return [];
      }),
  ]);

  const mode = surface?.mode.mode ?? "GATE-BLOCKED";
